
import { createOpenAI } from '@ai-sdk/openai';
import { createGoogleGenerativeAI } from '@ai-sdk/google';
import { streamText } from 'ai';
import { getSiteContext } from '@/lib/ai-context';
import { generateChatResponse } from '@/lib/local-ai';

// Initialize providers lazily or safely
const getOpenAI = (apiKey: string) => createOpenAI({ apiKey });
const getGemini = (apiKey: string) => createGoogleGenerativeAI({ apiKey });

export const maxDuration = 30;

export async function POST(req: Request) {
    try {
        const { messages } = await req.json();

        // 0. CHECK FOR KEYS - If none, go straight to Local AI to avoid hanging
        const openAIKey = process.env.OPENAI_API_KEY || process.env.NEXT_PUBLIC_OPENAI_KEY;
        const geminiKey = process.env.GOOGLE_GENERATIVE_AI_API_KEY || process.env.NEXT_PUBLIC_GEMINI_KEY || process.env.GEMINI_API_KEY;

        // Fetch site context (non-blocking)
        let siteContext = "";
        try { siteContext = await getSiteContext(); } catch (e) { console.log("Context fetch error", e); }

        const systemPrompt = `You are CareerPilot, an expert AI career counselor for High School and University students in Sierra Leone.
        
Your Role:
- Guide users to suitable career paths based on their interests.
- Suggest relevant Sierra Leonean universities (FBC, Njala, UNIMAK, etc.) and online courses.
- Provide realistic salary expectations in Sierra Leonean Leones (SLE) and USD.
- Be encouraging, professional, and practical.
- If asked about "Health", "Tech", "Agric", etc., detail specific jobs and requirements.

REAL-TIME SITE DATA:
${siteContext || 'No real-time data available.'}

Context:
- Users are often young students or job seekers.
- Keep answers concise and bulleted for readability.
- ALWAYS tailor advice to the Sierra Leone context (e.g. mention local companies, challenges like power/internet).`;

        // 1. Try OpenAI
        if (openAIKey && openAIKey.startsWith('sk-')) {
            try {
                // console.log("Attempting OpenAI...");
                const openai = getOpenAI(openAIKey);
                const result = await streamText({
                    model: openai('gpt-4o'),
                    system: systemPrompt,
                    messages,
                });
                return result.toTextStreamResponse();
            } catch (err: any) {
                console.error("OpenAI failed, failing over...", err.message);
            }
        }

        // 2. Try Gemini
        if (geminiKey && geminiKey.length > 10) {
            try {
                console.log("Attempting Gemini...");
                const google = getGemini(geminiKey);
                const result = await streamText({
                    model: google('gemini-1.5-flash'),
                    system: systemPrompt,
                    messages,
                });
                return result.toTextStreamResponse();
            } catch (err: any) {
                console.error("Gemini failed, failing over...", err.message);
            }
        }

        // 3. Local AI Fallback (Absolute Guarantee)
        console.log("Using Local AI (No keys or API failure)");
        const localResponse = await generateChatResponse(messages, siteContext);

        // Stream the text manually to satisfy useChat
        const encoder = new TextEncoder();
        const stream = new ReadableStream({
            async start(controller) {
                const chunks = localResponse.split(/(?=[,.\n])/);
                for (const chunk of chunks) {
                    controller.enqueue(encoder.encode(chunk));
                    await new Promise(r => setTimeout(r, 20)); // fast typing speed
                }
                controller.close();
            }
        });

        return new Response(stream, {
            headers: { 'Content-Type': 'text/plain; charset=utf-8' }
        });

    } catch (error) {
        console.error("Chat Route Critical Failure:", error);
        // Return a safe fallback even on critical error
        return new Response("I am currently having connection issues, but I am here to help. Please try asking about 'salaries' or 'universities'.", {
            headers: { 'Content-Type': 'text/plain' }
        });
    }
}
